{"name": "handle_external_webhook", "kind": "normal", "code": "import hashlib
import hmac
import json
from datetime import datetime, timezone

def handle_external_webhook(payload: dict, signature: str, secret: str, timestamp: str = None):
    """
    处理外部 webhook POST 请求：
    1. 验证 HMAC-SHA256 签名
    2. 将数据落库（这里模拟落库，实际可替换为数据库写入）

    参数:
        payload: 请求体 JSON 解析后的字典
        signature: 请求头或参数中携带的签名值（hex 格式）
        secret: 与 webhook 发送方约定的共享密钥
        timestamp: 可选，ISO 格式时间戳，用于防重放攻击
    """
    # 1. 构造待签名字符串
    if timestamp:
        # 防重放：检查时间戳是否在可接受窗口内（例如 300 秒）
        try:
            ts = datetime.fromisoformat(timestamp)
            now = datetime.now(timezone.utc).replace(tzinfo=None)
            if abs((now - ts).total_seconds()) > 300:
                return {"success": False, "error": "Timestamp too old, possible replay attack"}
        except ValueError:
            return {"success": False, "error": "Invalid timestamp format"}
        message = f"{timestamp}.{json.dumps(payload, sort_keys=True)}"
    else:
        message = json.dumps(payload, sort_keys=True)

    # 2. 验证签名
    expected = hmac.new(
        secret.encode('utf-8'),
        message.encode('utf-8'),
        hashlib.sha256
    ).hexdigest()

    if not hmac.compare_digest(expected, signature):
        return {"success": False, "error": "Invalid signature"}

    # 3. 落库（示例：写入结构化日志/内存存储，实际可替换为数据库写入）
    record = {
        "event": payload.get("event", "unknown"),
        "data": payload,
        "received_at": datetime.utcnow().isoformat(),
        "verified": True
    }

    # 实际项目中此处可写入数据库
    # db.insert("webhook_events", record)

    return {
        "success": True,
        "message": "Webhook event processed and stored",
        "record_id": hashlib.md5(json.dumps(record, sort_keys=True).encode()).hexdigest()
    }
", "description": "处理外部 webhook POST 请求，使用 HMAC-SHA256 验证签名，验证通过后将事件数据落库存储"}
